+// Utility
+// ---------------------------------------------------------------------------
+
+/// Simple deterministic hash (FNV-1a) for content hashing.
+fn compute_simple_hash(data: &[u8]) -> String {
+    let mut hash: u64 = 0xcbf29ce484222325;
+    for &byte in data {
+        hash ^= byte as u64;
+        hash = hash.wrapping_mul(0x100000001b3);
+    }
+    format!("{hash:016x}")
+}
